package com.architectureworkbench.api;
import com.architectureworkbench.api.ApiDtos.*; import com.architectureworkbench.audit.*; import com.architectureworkbench.workspace.*;
import java.nio.file.Files; import java.time.Instant; import java.util.*; import org.junit.jupiter.api.Test; import static org.junit.jupiter.api.Assertions.*;
class ProductCompositionServiceTest {
 @Test void composesMultipleRepositoriesPreservingProvenanceAndAmbiguity() throws Exception {var root=Files.createTempDirectory("products");String w="workspace-test";Files.createDirectories(root.resolve(w));var mapper=new com.fasterxml.jackson.databind.ObjectMapper();var runStore=new FileDiscoveryRunReadRepository(root,mapper);runStore.save(run(w,"run-a","event-contract","ApplicationSubmitted","2","orders","Order"));runStore.save(run(w,"run-b","event-contract","ApplicationSubmitted","2","loans","Order"));var audit=new InMemoryAuditSink();var store=new FileProductRepositoryStore(root,mapper);var service=new ProductCompositionService(store,runStore,audit);var product=service.create(w,new CreateProductRequest("Mortgage","", "tester"));product=service.addRepository(w,product.productId(),new AddProductRepositoryRequest("orders",root.toString(),"SERVICE",List.of("run-a"),Map.of("release","1"),Map.of("team","orders"),"tester"));product=service.addRepository(w,product.productId(),new AddProductRepositoryRequest("loans",root.toString(),"SERVICE",List.of("run-b"),Map.of(),Map.of(),"tester"));product=service.createModule(w,product.productId(),new CreateProductModuleRequest("LOS","","APPLICATION","tester"));product=service.assign(w,product.productId(),product.modules().get(0).moduleId(),product.repositories().get(0).repositoryId(),"tester");var c=service.compose(w,product.productId(),"tester");assertEquals(2,c.contributions().size());assertEquals(2,c.evidence().size());assertEquals("run-a",c.evidence().get(0).discoveryRunId());assertEquals("contract-plugin",c.evidence().get(0).evidence().provenance().provenance());assertEquals(1,c.identities().size());assertFalse(c.relationships().isEmpty());assertEquals(2,c.metrics().repositoryCount());assertEquals(50d,c.metrics().ownershipMetadataCoverage());var reload=new FileProductRepositoryStore(root,mapper);assertEquals(2,reload.find(w,product.productId()).orElseThrow().repositories().size());assertEquals(c.evidence().size(),reload.composition(w,product.productId()).orElseThrow().evidence().size());assertTrue(new FileWorkspaceIntegrityService(root).verifyWorkspace(WorkspaceId.of(w)).valid());assertTrue(audit.entries().stream().anyMatch(e->e.action().equals("ProductCompositionGenerated")));}
 @Test void isolatesWorkspacesAndRetainsAmbiguousSimpleNames() {var runs=new InMemoryDiscoveryRunReadRepository();runs.save(run("w","a","java-class","com.a.Order","","a","Order"));runs.save(run("w","b","java-class","com.b.Order","","b","Order"));var service=new ProductCompositionService(new InMemoryProductRepositoryStore(),runs,new InMemoryAuditSink());var p=service.create("w",new CreateProductRequest("P","","x"));p=service.addRepository("w",p.productId(),new AddProductRepositoryRequest("a","/a","SERVICE",List.of("a"),Map.of(),Map.of(),"x"));p=service.addRepository("w",p.productId(),new AddProductRepositoryRequest("b","/b","SERVICE",List.of("b"),Map.of(),Map.of(),"x"));assertEquals(1,service.compose("w",p.productId(),"x").conflicts().size());assertTrue(service.list("other").isEmpty());}
 private DiscoveryRunDetails run(String w,String id,String type,String identity,String version,String source,String symbol){var confidence=new DiscoveryConfidenceView(1,100,"HIGH","explicit");var provenance=new DiscoveryProvenanceView("src/"+symbol+".java",".",identity.contains(".")?identity.substring(0,identity.lastIndexOf('.')):"",symbol,1,source,"contract-plugin");Map<String,String> attrs=new LinkedHashMap<>();if(type.contains("contract")){attrs.put("contractId",identity);attrs.put("eventName",identity);attrs.put("contractVersion",version);}else attrs.put("packageName",identity);var evidence=new DiscoveryEvidenceView("e-"+id,type,identity,identity,provenance,confidence,"OBSERVED",List.of(),"explicit",null,attrs);var summary=new DiscoveryRunSummary(id,w,source,"COMPLETED",Instant.now(),Instant.now(),"c","cause",1,1,0,0,0,0,false);return new DiscoveryRunDetails(summary,List.of(),List.of(evidence),List.of(),List.of(),List.of(),Map.of("HIGH",1));}
}
